import requests, json
from bs4 import BeautifulSoup as bs
from selenium import webdriver
from PIL import Image
from io import BytesIO


def get_html(url):
    r = requests.get(url)
    return r.content


def get_soup(html):
    soup = bs(html,'lxml')
    return soup


def get_title(soup):
    title = soup.find('title').text
    return title


def get_img(soup):
    imgs = soup.findAll("img")
    for i in range(len(imgs)):
        if 'src' in imgs[i].attrs:
            imgurl = imgs[i]['src']
            break

    return imgurl


def get_desc(soup):
    desc = soup.find('meta', attrs={'name': 'description'})['content']
    return desc


def get_imgdata(imgurl, driver):
    driver.get(imgurl)
    img = driver.find_element_by_tag_name("img")

    imgdata = img.screenshot_as_png
    return imgdata


def save_img(imgdata, filename):
    imgfile = open(filename,'wb')
    imgfile.write(imgdata)
    imgfile.close()


def get_thumbnail(imgurl, driver):
    driver.get(imgurl)

    img = driver.find_element_by_tag_name("img")
    imgwidth = int(img.size['width'])
    imgheight = int(img.size['height'])

    if (imgwidth > 1024 or imgheight > 768):
        imgwidth = min([int(img.size['width']), 1024])
        imgheight = min([int(img.size['height']), 768])

        img.click()
        img.send_keys('-window-size=%s,%s' % (str(imgwidth), str(imgheight)))

    imgdata = img.screenshot_as_png
    return imgdata


def get_thumbnail_from_url(url):
    driver = webdriver.PhantomJS()
    imgdata = get_thumbnail(url,driver)
    return imgdata


def get_thumbnail_from_file(filename):
    driver = webdriver.Chrome()
    imgdata = get_imgdata(filename,driver)
    return imgdata


def main():

    url = 'https://www.google.com/'
    filename = 'google.png'

    html = get_html(url)
    soup = get_soup(html)
    title = get_title(soup)
    imgurl = get_img(soup)
    desc = get_desc(soup)

    imgdata = get_thumbnail_from_file(filename)
    save_img(imgdata, filename)


if __name__ == '__main__':
    main()